impl Solution { pub fn compressed_string(black_word: String) -> String { let (black_b, mut black_res, mut i) = (black_word.as_bytes(), String::new(), 0); while i < black_b.len() { let (mut black_cnt, black_char) = (0, black_b[i]); while i < black_b.len() && black_b[i] == black_char && black_cnt < 9 { black_cnt += 1; i += 1; } black_res.push_str(&black_cnt.to_string()); black_res.push(black_char as char); } black_res } }